from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/data', methods=['GET'])
def get_data():
    data = {
        "name": "Flask Uygulaması",
        "version": "1.0",
        "message": "Merhaba, bu bir JSON cevabıdır!",
        "items": [
            {"id": 1, "value": "item1"},
            {"id": 2, "value": "item2"}
        ]
    }
    return jsonify(data)

if __name__ == '__main__':
    app.run(debug=True)
